const fs = require('fs');

const RAW = '/home/makaron8426/Sync/oikos/mneme/.hegemonikon/paper_sentinel_raw.json';
const OUT = '/home/makaron8426/Sync/oikos/mneme/.hegemonikon/paper_sentinel.json';
const now = new Date();

let raw = {};
try { raw = JSON.parse(fs.readFileSync(RAW, 'utf-8')); } catch(e) {
  return [{ json: { error: e.message, hasPapers: false, shouldAlert: false } }];
}

const papers = raw.papers || [];
const highScore = papers.filter(p => (p.score || 0) >= 0.7);
const hasPapers = papers.length > 0;
const shouldAlert = highScore.length > 0;

const result = {
  timestamp: now.toISOString(),
  topics: raw.topics || [],
  totalPapers: papers.length,
  highScorePapers: highScore.length,
  hasPapers,
  shouldAlert,
  topPapers: papers.slice(0, 5).map(p => ({
    title: p.title,
    score: p.score,
    topic: p.topic,
    abstract: (p.abstract || '').substring(0, 200)
  }))
};

fs.writeFileSync(OUT, JSON.stringify(result, null, 2), 'utf-8');

// Build notification payload
let notifyPayload = '';
if (shouldAlert) {
  const paperList = highScore.slice(0, 3).map(p =>
    '• *' + p.title + '* (score: ' + (p.score || 0).toFixed(2) + ', topic: ' + p.topic + ')'
  ).join('\n');
  notifyPayload = JSON.stringify({
    blocks: [
      { type: 'header', text: { type: 'plain_text', text: '📚 Paper Sentinel: ' + highScore.length + ' high-score papers', emoji: true } },
      { type: 'section', text: { type: 'mrkdwn', text: paperList } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: '_WF-14 | Topics: ' + (raw.topics || []).join(', ') + '_' }] }
    ]
  });
}

return [{ json: Object.assign(result, { notifyPayload }) }];

const fs = require('fs');
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const dir = '/home/makaron8426/Sync/oikos/mneme/.hegemonikon/sentinel/';

try { fs.mkdirSync(dir, { recursive: true }); } catch(e) {}

const summary = $input.first().json;
const cortexResp = $('Cortex要約').first().json;

const report = `# Paper Sentinel Report — ${dateStr}\n\n` +
  `> Topics: ${(summary.topics || []).join(', ')}\n` +
  `> Total: ${summary.totalPapers}, High-score: ${summary.highScorePapers}\n\n` +
  `## Cortex Analysis\n\n${cortexResp.text || '(no response)'}\n\n` +
  `## Top Papers\n\n` +
  (summary.topPapers || []).map(p =>
    `### ${p.title}\n- Score: ${p.score}\n- Topic: ${p.topic}\n- ${p.abstract}\n`
  ).join('\n');

const reportFile = dir + 'paper_sentinel_' + dateStr + '.md';
fs.writeFileSync(reportFile, report, 'utf-8');

return [{ json: { reportFile, status: 'saved' } }];
